import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"勒拿之息","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/0.无支线/勒拿之息.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/0.无支线/勒拿之息.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/0.无支线/勒拿之息.md"};function l(p,a,_,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"勒拿之息",tabindex:"-1"},[s("勒拿之息 "),e("a",{class:"header-anchor",href:"#勒拿之息","aria-label":'Permalink to "勒拿之息"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌035")])])],-1),o('<h1 id="勒拿之息-1" tabindex="-1">勒拿之息 <a class="header-anchor" href="#勒拿之息-1" aria-label="Permalink to &quot;勒拿之息&quot;">​</a></h1><p>勒拿之息<br> 价格：1500<br> 本质：特异<br> 用九头蛇勒拿的第七颗头颅骸骨磨成的银质舌钉，三世纪时，亚历山大城的诺斯替教徒从勒拿沼泽深处将其掘出，用秘银熔化骸骨的齿根，混合九头蛇心脏流出的黑血，在血祭仪式中锻造而成。钉身缠绕着凝固的蛇血纹路，在月光下会渗出腥甜的雾气。</p><p>佩戴者需要将舌钉会刺入舌筋，以激活九头蛇的再生诅咒，佩戴过程中会导致1点剧痛，使用意志豁免进行对抗，DC为3。</p><p>效果：迅捷动作激活舌钉，佩戴者的舌头会立刻疯涨，过程伴随着令人牙酸的肌肉撕裂声增长到3米，表面迅速覆盖一层滑腻的分泌物，根部会先鼓起环状的褶皱，如同触手的体节，这些褶皱能自由收束，让舌头在生长时可以灵活地弯折，甚至像蛇一样缠绕住横梁，在使用时，如同使用一支肢体一般，且被视为肢体。此时，佩戴者可以将这伸长的舌头视为具有3L伤害的天生武器。<br> 显然的，在舌头伸长的状态下，佩戴者说话将变得含糊不清，无法使用语言要素。将变长的舌头收回则是一个标准动作。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
